function ModelEndles:OnPlayerEndLessSpecialResp(pb)
    --无尽试炼初始化
    local specialType = pb.specialType          --今日开启的特殊试炼类型
    local maxNode = pb.maxNode                  --综合试炼最大通关关卡Id      用于判断特殊试炼开启
    local nextFlushTime = pb.nextFlushTime      --本轮刷新时间    用于轮换预告
    self._specialType = specialType
    self._nextFlushTime = nextFlushTime
    self._maxNode = maxNode

    self:OnPlayerEndLessInfoReq(ModelEndles.ENDLES_COMPLEX)
    local ref = self:GetEndlessRefByRefId(specialType)
    if ref then
        self:OnPlayerEndLessInfoReq(ref.type)
    end
end

function ModelEndles:OnPlayerEndLessInfoResp(pb)
    --无尽试炼信息返回
    local type = pb.type                        --无尽试炼类型
    local maxNode = pb.maxNode                  --历史最大关卡Id
    local battleType = pb.battleType            --今日挑战无尽试炼类型 参考EndlessType枚举 0表示未挑战
    local lastBuff = pb.lastBuff or 0                --上次战斗选择buff，0表示未选择
    self:SetIsEndlessFight(pb.isBattle)
    if (type == ModelEndles.ENDLES_COMPLEX) then
        --self._maxNode = maxNode
        self:SetMaxNode(maxNode)
    end
    self:SetCurrSpecialType(battleType)
    local receiveIds = pb.receiveIds            --已领取通关奖励Id
    local _receiveIds = {}
    for i, v in ipairs(receiveIds) do
        _receiveIds[v] = v
    end
    local helpHero = pb.helpHero                --援助英雄（可为空）
    local _helpHero
    if (helpHero) then
        _helpHero = StructEndlessHeroInfo:New()
        _helpHero:CreateByPb(helpHero)
    end
    local _endlesInfo = {
        type = type, --无尽试炼类型
        selfRank = pb.selfRank, --试炼排名 （0表示未上榜）
        initNode = pb.initNode, --初始关卡Id
        maxNode = maxNode, --历史最大关卡Id
        dayNode = pb.dayNode, --今日最大关卡Id
        battleType = battleType, --今日挑战无尽试炼类型 参考EndlessType枚举 0表示未挑战
        receiveIds = _receiveIds, --已领取通关奖励Id
        helpHero = _helpHero, --援助英雄（可为空）
        nowNode = pb.nowNode, --当前战斗关卡Id
        lastBuff = lastBuff,
    }
    if not self._endlessInfo then
        self._endlessInfo = {}
    end
    self._endlessInfo[type] = _endlesInfo

    local buffList = pb.buffList               --下轮随机BuffIds
    self._buffList = {}
    for i, v in ipairs(buffList) do
        table.insert(self._buffList, v)
    end
    local itemList = pb.itemList                --战斗累积奖励（战斗中使用）
    self._itemList = {}
    if (itemList) then
        for i, v in ipairs(itemList) do
            local item = StructRewardItem:New()
            item:CreateByPb(v)
            table.insert(self._itemList, item)
        end
    end
    local battleHeroList = pb.battleHeroList    --战斗英雄状态属性（战斗中使用）
    self._battleHeroList = {}
    for i, v in ipairs(battleHeroList) do
        local battleHero = StructEndlessHeroInfo:New()
        battleHero:CreateByPb(v)
        table.insert(self._battleHeroList, battleHero)
    end
    self._specialType = pb.specialType          --今日开启的特殊试炼类型
    self._nowBuff = pb.nowBuff                  --当前选择buff
    if self._haveNewSelect then
        FireEvent(EventNames.ON_ENDLESS_BUFF_SELECT)
        self:StartSelectTimer()
    end

    if battleType > 0 then
        FireEvent(EventNames.ON_ENDLESS_BATTLE, battleType)
    end

    FireEvent(EventNames.ON_BATTLE_MODEL_DATA_OK)
end

function ModelEndles:OnHelpHeroListResp(pb)
    --援助英雄列表返回
    local type = pb.type                    --无尽试炼类型
    local heroList = pb.heroList            --援助英雄列表
    local helpHero = pb.helpHero            --已选援助英雄（可为空）
    local selfHero = pb.selfHero            --自身的援助英雄（可为空）
    local _heroList = {}
    local _helpHero, _selfHero
    for i, v in ipairs(heroList) do
        local hero = StructEndlessHeroInfo:New()
        hero:CreateByPb(v)
        _heroList[v.id] = hero
    end
    if (helpHero) then
        _helpHero = StructEndlessHeroInfo:New()
        _helpHero:CreateByPb(helpHero)
    end
    if (selfHero) then
        _selfHero = StructEndlessHeroInfo:New()
        _selfHero:CreateByPb(selfHero)
    end
    local _endlessHelp = {
        type = type,
        heroList = _heroList,
        helpHero = _helpHero,
        selfHero = _selfHero,
    }
    self._endlessHelp[type] = _endlessHelp
    local _endlessInfo = self._endlessInfo[type]
    if not _endlessInfo then
        return
    end
    _endlessInfo.helpHero = _helpHero
end

function ModelEndles:OnSelectHelpHeroResp(pb)
    --选择援助英雄返回
    local type = pb.type                    -- --选择类型 1：雇佣英雄 ， 2： 上阵援助英雄 3： 取消雇佣
    local id = pb.id                        --英雄流水Id
    local endlessType = pb.endlessType      --雇佣英雄使用， 无尽试炼类型
    local playerId = pb.playerId            --雇佣英雄使用， 玩家Id
    local _endlessHelp = self:GetEndlessHelp(endlessType)
    if (not _endlessHelp) then
        self:OnHelpHeroListReq(endlessType)
        return
    end
    local _endlessInfo = self._endlessInfo[endlessType]
    if (not _endlessInfo) then
        self:OnPlayerEndLessInfoReq(endlessType)
        return
    end
    if (type == 1) then
        local heroInfo = _endlessHelp.heroList[id]
        _endlessHelp.helpHero = heroInfo
        _endlessInfo.helpHero = heroInfo
    elseif (type == 2) then

        local heroList = gModelHero:GetHeroList()
        ---@type StructHero
        local heroInfo = heroList[id]
        local selfHero = {
            refId = heroInfo:GetRefId(),
            id = heroInfo:GetId(),
            heroType = 1,
            lvl = heroInfo:GetLv(),
            star = heroInfo:GetStar(),
            grade = heroInfo:GetGrade(),
            power = heroInfo:GetPower(),
            isResonance = heroInfo:GetResonanceStatus(),
            skin = heroInfo:GetSkin(),
            treeInfo = heroInfo:GetTreeInfo(),
            form = heroInfo.form,
        }
        _endlessHelp.selfHero = selfHero
    elseif (type == 3) then
        _endlessHelp.helpHero = nil
        _endlessInfo.helpHero = nil
    end
end

function ModelEndles:OnReceiveNodeRewardResp(pb)
    --领取通关奖励返回
    local type = pb.type                    --无尽试炼类型
    local node = pb.node                    --奖励关卡Id
    local endlesInfo = self._endlessInfo[type]
    if (not endlesInfo) then
        return
    end
    endlesInfo.receiveIds[node] = node
    self._endlessInfo[type] = endlesInfo
end

function ModelEndles:OnSelectBuffResp(pb)
    local type = pb.type
    local overTime = pb.overCombatTime / 1000 --上一场战斗结束时间

    self:SetCurrSpecialType(type)
    self:InitEndlessInfo(type)

    local cfg = self:GetEndlessRefByType(type)
    local combatType = cfg.combatTyep
    gModelBattle:CancelWaitReqCombat(combatType)

    local endTime = nil
    self._haveNewSelect = true --需要选buff
    local delayTime = GameTable.EternalConfigRef["autoSelectTime"]
    if overTime == 0 then
        endTime = GetTimestamp() + delayTime
    else
        endTime = overTime + delayTime
    end
    self._selectBuffTime = endTime
    local info = self._endlessInfo[type]
    if not info then
        --数据未初始化
        return
    end
    FireEvent(EventNames.ON_ENDLESS_BUFF_SELECT)

    self:StartSelectTimer()
end
