function ModelEndles:ClearNewSelectBuff()

    if self._haveNewSelect == false then
        return
    end
    self._haveNewSelect = false
    FireEvent(EventNames.ON_ENDLESS_BUFF_SELECTEND)
    if self._timer then
        self._timer:TimerRemoveByKey(self._selectBuffKey)
    end

end

function ModelEndles:GetMaxNode()
    --获取综合试炼的最大关卡
    local checkNode = self._maxNode or 0
    if checkNode > 0 then
        local ref = self:GetEndlessCheckpointRefByRefId(checkNode)
        checkNode = ref.id
    end

    return checkNode
end

function ModelEndles:SetMaxNode(node)
    local oldNode = self._maxNode
    self._maxNode = node
    if oldNode and node and oldNode ~= node then

        local checkNode = node
        if checkNode > 0 then
            local ref = self:GetEndlessCheckpointRefByRefId(checkNode)
            checkNode = ref.id
        end

        FireEvent(EventNames.ON_ENDLESS_NODE_CHANGE, checkNode)
    end
end
