function ModelEndles:GetTabList()
    --获取界面标签
    local zType = ModelEndles.ENDLES_COMPLEX--综合类型试炼写死
    local zRef = self:GetEndlessRefByType(zType)
    local list = {
        { type = zType, name = ccLngText(zRef.name) },
    }

    local cType = self:GetSpecialType()
    if (cType) then
        local cRef = self:GetEndlessRefByRefId(cType)
        if cRef then
            local data = { type = cRef.type, name = ccLngText(cRef.name) }
            table.insert(list, data)
        end
    end

    return list
end

function ModelEndles:GetUnclaimedAward(type, receiveIds)
    local firstList = self:GetFirstOpenRefByType(type)
    local unclaimedList = {}
    for i, v in pairs(firstList) do


        if (not receiveIds[v.refId]) then
            table.insert(unclaimedList, v)
        end

    end
    table.sort(unclaimedList, function(a, b)
        return self:Sort(a, b)
    end)
    return unclaimedList[1]
end

function ModelEndles:GetFirstAwardList(type, maxRefId, receiveIds)
    local firstList = self:GetFirstOpenRefByType(type)
    local _list = {}
    for i, v in pairs(firstList) do
        table.insert(_list, v)
    end
    table.sort(_list, function(a, b)
        return self:Sort(a, b)
    end)
    local list = {}
    local len = 10 --预览10个
    for i, v in ipairs(_list) do
        if (v.refId >= maxRefId and len >= 0 and not receiveIds[v.refId]) then
            table.insert(list, v)
            len = len - 1
        end
    end
    return list
end

function ModelEndles:GetCheckAwardList(type, initNode)
    local checkList = self:GetCheckPointRefByType(type)
    local _list = {}
    for i, v in pairs(checkList) do
        table.insert(_list, v)
    end
    table.sort(_list, function(a, b)
        if (a.id ~= b.id) then
            return a.id < b.id
        end
        return false
    end)
    local list = {}
    local len = 10 --预览10个
    for i, v in ipairs(_list) do
        if (v.refId >= initNode and len >= 0) then
            table.insert(list, v)
            len = len - 1
        end
    end
    return list
end

function ModelEndles:Sort(a, b)
    local aSort = a.sort
    local bSort = b.sort
    if (aSort ~= bSort) then
        return aSort < bSort
    end
    return false
end

function ModelEndles:GetIsRace(specialType, race)
    if (specialType == 1 or race == 0) then
        return race
    end
    local ref = self:GetEndlessRefByType(specialType)
    local raceArr = string.split(ref.race, ",")
    local currRece = tonumber(raceArr[1])
    for i, v in ipairs(raceArr) do
        local iRece = tonumber(v)
        if (race == iRece) then
            return iRece
        end
    end
    return currRece
end

function ModelEndles:GetEndlessRefIdByType(specialType)
    local typeToRefId = self._typeToRefId
    if typeToRefId then
        return typeToRefId[specialType]
    end
    typeToRefId = {}
    local ref = self:GetModelConfig(ModelEndles.EternalRef)
    for k, v in pairs(ref) do
        typeToRefId[v.type] = v.refId
    end

    self._typeToRefId = typeToRefId

    return typeToRefId[specialType]
end

function ModelEndles:GetRaceRecord(specialType)
    local parseFunc = function(value)
        local numList = LxDataHelper.ParseNumber_Sign(value, ',')
        local record = {}
        for k, v in ipairs(numList) do
            record[v] = true
        end
        return record
    end

    local refId = self:GetEndlessRefIdByType(specialType)
    local record = self:GetConfigValueImpl(ModelEndles.EternalRef, refId, "race", parseFunc)
    return record

end

function ModelEndles:GetRaceMaxPower(specialType)
    local ref = self:GetEndlessRefByType(specialType)
    local raceArr = string.split(ref.race, ",")
    local _maxPower = 0
    for i, v in ipairs(raceArr) do
        local iRece = tonumber(v)
        local power = gModelHero:GetMaxPowerHeroPower(iRece)
        if (_maxPower < power) then
            _maxPower = power
        end
    end
    return _maxPower
end

function ModelEndles:GetEndlessConfigRefByKey(key)
    return GameTable.EternalConfigRef[key]
end

function ModelEndles:GetIsBasicsReward(initNode, dayNode)
    local round = self:GetEndlessConfigRefByKey("basicsRewardRound")
    local initRef = self:GetEndlessCheckpointRefByRefId(initNode)
    local dayRef = self:GetEndlessCheckpointRefByRefId(dayNode)
    if (not dayRef or dayRef.id > initRef.id + round) then
        return false
    end
    return true
end

function ModelEndles:GetEndlessRef()
