end

function ModelEndles:GetEndlessRefByType(type)
    local ref = self:GetEndlessRef()
    for i, v in pairs(ref) do
        if (type == v.type) then
            return v
        end
    end
end

function ModelEndles:GetEndlessRefByCombatTyep(combatTyep)
    local ref = self:GetEndlessRef()
    for i, v in pairs(ref) do
        if (combatTyep == v.combatTyep) then
            return v
        end
    end
end

function ModelEndles:GetEndlessRefByRefId(refId)
    local ref = self:GetEndlessRef()
    return ref[refId]
end

function ModelEndles:GetEndlessCheckpointRefByRefId(refId)
    local ref = GameTable.EternalCheckpointRef[refId]
    if not ref then
        if LOG_INFO_ENABLED then
            print("ref missing GameTable.EternalCheckpointRef ")
        end
        printInfoNR2("缺少配置", string.format("GameTable.EternalCheckpointRef, refId = %s", refId or "nil"))
    end
    return ref
end

