function ModelEndles:GetEndlessRankRefByType(type)
    local list = {}
    for i, v in pairs(GameTable.EndlessRankRef) do
        if (v.type == type) then
            table.insert(list, v)
        end
    end
    table.sort(list, function(a, b)
        return a.sort < b.sort
    end)
    return list
end

function ModelEndles:GetEndlessRankRefByRank(type, rank)
    local list = self:GetEndlessRankRefByType(type)
    for i, v in pairs(list) do
        local rankArr = string.split(v.rank, ",")
        if (tonumber(rankArr[1]) <= rank and rank <= tonumber(rankArr[2])) then
            return v
        end
    end
    return list[#list]
end

function ModelEndles:GetEndlessBuffRefByRefId(refId)
    return GameTable.EternalBuffRef[refId]
end

function ModelEndles:GetEndlessBuffRefBySkillId(skillId)
    for i, v in pairs(GameTable.EternalBuffRef) do
        if (v.addAttrSkill == skillId) then
            return v
        end
    end
end

function ModelEndles:InitEndlessFirstOpenRefOnType()
    self._checkPointRefData = {}
    self._firstOpenRefData = {}
    for i, v in pairs(GameTable.EternalCheckpointRef) do
        local checkPointRef = self._checkPointRefData[v.type]
        if (not checkPointRef) then
            checkPointRef = {}
        end
        checkPointRef[v.refId] = v
        self._checkPointRefData[v.type] = checkPointRef
    end
    for i, v in pairs(GameTable.EternalFirstOpenRef) do
        local firstOpenRef = self._firstOpenRefData[v.type]
        if (not firstOpenRef) then
            firstOpenRef = {}
        end
        --统一检查不做地区隔离
        local getRef = gModelEndles:GetEndlessCheckpointRefByRefId(v.refId)
        if getRef then
            firstOpenRef[v.refId] = v
            self._firstOpenRefData[v.type] = firstOpenRef
        end

    end
end

function ModelEndles:NeedShowBuffSelect(targetType)
    local netData = self:GetEndlesData(targetType)

    if not netData then
        return false
    end

    if netData.nowNode == 0 then
        return true
    end

    return false
end

function ModelEndles:InitEndlessInfo(type)
    local cfg = self:GetEndlessRefByType(type)
    local combatType = cfg.combatTyep
    local formation = gModelFormation:GetFormation(combatType)
    if not formation then
        gModelFormation:OnGetFormationReq(combatType)
    end

    local endlessInfo = self._endlessInfo[type]
    if not endlessInfo then
        self:OnPlayerEndLessInfoReq(type)
    end
end

function ModelEndles:GetBattleMap(combatType)
    local ref = self:GetEndlessRefByCombatTyep(combatType)
    local targetType = ref.type
    local netData = self:GetEndlesData(targetType)

    if not netData then
        return
    end

    local nowNode = netData.nowNode
    if nowNode == 0 then
        nowNode = netData.initNode
    end

    local cfg = self:GetCheckPointRefByTypeRefId(targetType, nowNode)
    if cfg then
        return cfg.map
    end

end

function ModelEndles:FormatEndlessCombatData()
    local info = self:GetCurrTypeEndlesData()
    if not info then
        printErrorN("没有无尽试炼信息 当前类型 " .. (self._currSpecialType or "nil"))
        return
    end
    local ref = gModelEndles:GetEndlessRefByType(info.type)
    local specialType = info.type
    local combatType = ref.combatTyep
    local meName = gModelPlayer:GetPlayerName()
    local otherName = ""
    local monsterId = gModelBattle:GetEndlesMonster({ specialType = specialType })
    if monsterId > 0 then
        local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
        otherName = ccLngText(monsterFormationRef.name)
    end

    local combatData = {
        combatType = combatType,
        --specialType = specialType,
        meName = meName,
        otherName = otherName,
    }

    local battleMapName = gModelBattle:GetBattleMapRes(combatData)
    combatData.battleMapName = battleMapName

    return combatData
end

function ModelEndles:GetEndlessTypeByCombatType(combatType)
    local combatTypeToEType = self._combatTypeToEType
    if combatTypeToEType then
        return combatTypeToEType[combatType]
    end

    combatTypeToEType = {}

    local ref = self:GetModelConfig(ModelEndles.EternalRef)
    for k, v in pairs(ref) do
        combatTypeToEType[v.combatTyep] = v.type
    end
    self._combatTypeToEType = combatTypeToEType
    return combatTypeToEType[combatType]

    --local ref = self:GetEndlessRefByCombatTyep(combatType)
    --if ref then
    --    return ref.type
    --end

end

function ModelEndles:GetCurNodeName()
    local info = self:GetCurrTypeEndlesData()
    if not info then
        return
    end
    local otherName = ""
    local monsterId = gModelBattle:GetEndlesMonster({ specialType = info.type })
    if monsterId > 0 then
        local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
        otherName = ccLngText(monsterFormationRef.name)
    end
    return otherName
end

function ModelEndles:GetPrepareEndelssHeroList(specialType, combatType, heroType)


    heroType = heroType or UIHeroRaceList.ALL_RACE_REFID
    local isShowTryHero = gModelBattle:CheckCombatPlayCampShowHeroFree(combatType)

    local raceRecord = gModelEndles:GetRaceRecord(specialType)

    local showCombatSpiritHeroStatus = gModelFormation:CheckCombatShowSpiritHero(combatType)

    local _heroList = {}
    --self._heroList = _heroList
    local heroList = gModelHero:GetHeroList()
    if heroList then
        for k, v in pairs(heroList) do
            local hero = v
            local refId = hero._refId
            local race = gModelHero:GetHeroRace(refId)
            local isIns = false
            if heroType == UIHeroRaceList.ALL_RACE_REFID or race == heroType then
                if showCombatSpiritHeroStatus then
                    --- 显示被链接的星灵英雄
                    if gModelSpiritHero:IsSpiritHeroRaceType(race) then
                        local linkRace = gModelSpiritHero:GetSpiritLinkHeroRace(v:GetId())
                        if linkRace and raceRecord[linkRace] then
                            if isShowTryHero or not v:IsTryHero() then
                                isIns = true
                            end
                        end
                    else
                        if raceRecord[race] ~= nil then
                            if isShowTryHero or not v:IsTryHero() then
                                isIns = true
                            end
                        end
                    end
                else
                    if raceRecord[race] ~= nil then
                        if isShowTryHero or not v:IsTryHero() then
                            isIns = true
                        end
                    end
                end
            end
            if isIns then
                local info = {
                    id = hero._id,
                    refId = refId,
                    heroType = 1, --1 = 玩家英雄，2 = 援助
                    star = hero._star,
                    lv = hero._level,
                    grade = hero._grade,
                    fightPower = hero._fightPower,
                    isResonance = hero._isResonance,
                    skin = hero._skin,
                    treeInfo = hero._treeInfo,
                    isTry = hero._isTry,
                    race = race,
                    form = hero.form
                }
                table.insert(_heroList, info)
            end
            --local _heroType = self:GetIsRace(specialType,race)
            --if _heroType == 0 or _heroType == race then
            --    table.insert(_heroList,info)
            --end
        end
    end
    local helpHero = self:GetHelpHeroData(specialType)
    if helpHero then
        if heroType == UIHeroRaceList.ALL_RACE_REFID or helpHero.race == heroType then
            table.insert(_heroList, helpHero)
        end
    end
    --local _specialType = specialType
    --local endlesInfo = self:GetEndlesData(specialType)
    --if endlesInfo.helpHero and not string.isempty(endlesInfo.helpHero.id)then
    --    local helpHero = endlesInfo.helpHero
    --    local refId = helpHero.refId
    --    local race = gModelHero:GetHeroRace(refId)
    --    local heroData =
    --    {
    --        playerId = helpHero.playerId,
    --        id = helpHero.id,
    --        refId = helpHero.refId,
    --        heroType = helpHero.heroType, 		--1 = 玩家英雄，2 = 援助
    --        star = helpHero.star,
    --        lv = helpHero.lvl,
    --        grade = helpHero.grade,
    --        fightPower = helpHero.power,
    --        isResonance = helpHero.isResonance,
    --        skin = helpHero.skin,
    --        treeInfo = helpHero.treeInfo,
    --        race = race,
    --    }
    --    table.insert(_heroList,heroData)
    --end
    --self._heroKeyList = {}
    --for i, v in ipairs(_heroList) do
    --    self._heroKeyList[v.id] = v
    --end
    table.sort(_heroList, function(a, b)
        if a.star ~= b.star then
            return a.star > b.star
        end
        if a.lv ~= b.lv then
            return a.lv > b.lv
        end
        if a.fightPower ~= b.fightPower then
            return a.fightPower > b.fightPower
        end
        if a.refId ~= b.refId then
            return a.refId < b.refId
        end
        return a.id < b.id
    end)
    return _heroList
end

function ModelEndles:GetHelpHeroData(specialType)
    local endlesInfo = self:GetEndlesData(specialType)
    if not endlesInfo then
        return
    end

    if not endlesInfo.helpHero then
        return
    end

    if string.isempty(endlesInfo.helpHero.id) then
        return
    end
    local helpHero = endlesInfo.helpHero
    local refId = helpHero.refId
    local race = gModelHero:GetHeroRace(refId)
    local heroData = {
        playerId = helpHero.playerId,
        id = helpHero.id,
        refId = helpHero.refId,
        heroType = helpHero.heroType, --1 = 玩家英雄，2 = 援助
        star = helpHero.star,
        lv = helpHero.lvl,
        grade = helpHero.grade,
        fightPower = helpHero.power,
        isResonance = helpHero.isResonance,
        skin = helpHero.skin,
        treeInfo = helpHero.treeInfo,
        race = race,
        form = helpHero.form,
    }
    return heroData
end

