function ModelEndles:GetEndlessHeroData(combatType, id)
    local eType = self:GetEndlessTypeByCombatType(combatType)
    local helpHero = self:GetHelpHeroData(eType)
    if helpHero and helpHero.id == id then
        return helpHero
    end

    local hero = gModelHero:GetHeroById(id)
    if hero then
        local refId = hero._refId
        local race = gModelHero:GetHeroRace(refId)
        local info = {
            id = hero._id,
            refId = refId,
            heroType = 1, --1 = 玩家英雄，2 = 援助
            star = hero._star,
            lv = hero._level,
            grade = hero._grade,
            fightPower = hero._fightPower,
            isResonance = hero._isResonance,
            skin = hero._skin,
            treeInfo = hero._treeInfo,
            isTry = hero._isTry,
            race = race,
            form = hero.form
        }

        return info
    end
end

