function ModelEndles:AutoSelectBuff()
    local buffList = self._buffList
    local cnt = #buffList
    local random = math.random(1, cnt)
    local buffId = buffList[random]
    local combatData = self:FormatEndlessCombatData()
    if not combatData then
        return
    end
    combatData.buffId = buffId
    combatData.isFromBuffWnd = true

    local isBack = true
    local curMap = GF.GetCurMap()
    if curMap and curMap:IsSameMap("LBattleMap") and curMap:IsReadyForCombat(combatData.combatType) then
        isBack = false
    end
    combatData.isBattleToBackground = isBack

    gModelBattle:StartEndlessBattle(combatData)
    self:ClearNewSelectBuff()
    GF.CloseWndByName("UIUendBfPop")
end

function ModelEndles:StartSelectTimer()
    local isGameNotReady = not GF.IsInMainScene() or LGameRunMode.IsLoading()
    if isGameNotReady then
        return
    end

    if not self._haveNewSelect then
        return
    end
    local endTime = self._selectBuffTime
    if not self._timer then
        self._timer = LxTimer:New()
    end
    self._timer:TimerRemoveByKey(self._selectBuffKey)
    local timeLeft = endTime - GetTimestamp()
    if timeLeft > 0 then
        self._timer:TimerCreate(self._selectBuffKey, function(key)
            if key == self._selectBuffKey then
                self:AutoSelectBuff()
            end
        end, timeLeft, true, 1)
    else
        self:AutoSelectBuff()
    end
    printInfoN("OnSelectBuffResp timeleft " .. timeLeft)

end




