function ModelEndles:GetCurFightCombatType()
    local info = self:GetCurrTypeEndlesData()
    if not info then
        return
    end

    local ref = self:GetEndlessRefByType(info.type)
    local combatType = ref.combatTyep

    return combatType
end

function ModelEndles:IsEndlessFighting()
    return self._isBattle == 1
end

function ModelEndles:SetIsEndlessFight(isBattle)
    self._isBattle = isBattle

    FireEvent(EventNames.ON_ENDLESS_FIGHT_STATE)
end

